#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *L = (long long*)malloc(N * sizeof(long long));
        long long *R = (long long*)malloc(N * sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &L[i]);
        for(int i=0;i<N;i++) scanf("%lld", &R[i]);
        long long ans = 0;
        for(int i=0;i<N-1;i++){
            long long cost = L[i+1] < R[i] ? L[i+1] : R[i];
            ans += cost;
        }
        printf("%lld\n", ans);
        free(L); free(R);
    }
    return 0;
}

